namespace YunTianYou.CodeGenerator.Core
{
    public interface ICodeGenerator
    {
        Task<GeneratedCode> GenerateEntityAsync(EntityModel model);
        Task<GeneratedCode> GenerateRepositoryAsync(EntityModel model);
        Task<GeneratedCode> GenerateServiceAsync(EntityModel model);
        Task<GeneratedCode> GenerateControllerAsync(EntityModel model);
        Task<GeneratedCode> GenerateReactComponentsAsync(EntityModel model);
    }

    public class CodeGenerator : ICodeGenerator
    {
        public async Task<GeneratedCode> GenerateEntityAsync(EntityModel model)
        {
            var template = await LoadTemplateAsync("EntityTemplate.cshtml");
            var code = await RenderTemplateAsync(template, model);
            return new GeneratedCode
            {
                FileName = $"{model.EntityName}.cs",
                Content = code,
                Language = "csharp"
            };
        }
    }
}
